// mm/src/api/downloadDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';
import { getAccessToken } from '../utils/auth';

const DEFAULT_API_BASE = 'https://manuscriptmagic.fowkes.xyz/services';
const API_BASE = process.env.REACT_APP_API_BASE_URL || DEFAULT_API_BASE;

function getFilenameFromContentDisposition(cd) {
  if (!cd) return '';
  const m = /filename\*?=(?:UTF-8''|")?([^;"\n]+)"?/i.exec(cd);
  if (!m?.[1]) return '';
  try {
    return decodeURIComponent(m[1]);
  } catch {
    return m[1];
  }
}

function extFromFilename(name = '') {
  const m = /\.([a-z0-9]+)$/i.exec(String(name).trim());
  return m?.[1]?.toLowerCase() || '';
}

function extFromMime(mime = '') {
  const t = String(mime).toLowerCase();
  if (t.includes('application/pdf')) return 'pdf';
  if (t.includes('application/vnd.openxmlformats-officedocument.wordprocessingml.document')) return 'docx';
  if (t.includes('application/msword')) return 'doc';
  if (t.includes('text/plain')) return 'txt';
  if (t.includes('text/markdown')) return 'md';
  if (t.includes('image/png')) return 'png';
  if (t.includes('image/jpeg')) return 'jpg';
  return '';
}

function ensureExtension(name, ext) {
  const trimmed = String(name || '').trim();
  if (!trimmed) return ext ? `document.${ext}` : 'document';
  if (/\.[a-z0-9]+$/i.test(trimmed)) return trimmed;
  return ext ? `${trimmed}.${ext}` : trimmed;
}

async function blobToText(blob) {
  try {
    return await blob.text();
  } catch {
    return '';
  }
}

function looksLikePdf(blob) {
  // PDF files begin with "%PDF"
  // We can do a cheap check by slicing first few bytes.
  return blob
    .slice(0, 4)
    .arrayBuffer()
    .then((buf) => {
      const bytes = new Uint8Array(buf);
      const s = String.fromCharCode(...bytes);
      return s === '%PDF';
    })
    .catch(() => false);
}

/**
 * Downloads raw blob from backend.
 * Backend should return the real file bytes.
 */
export async function downloadDocument(documentId) {
  if (!documentId) throw new Error('documentId is required');

  const url = `${API_BASE}/downloadDocument.php`;

  return withAuthRetry(async () => {
    const token = await getAccessToken();
    if (!token) throw new Error('Missing access token');

    console.log('⬇️ downloadDocument request:', { url, documentId });

    const resp = await axios.post(
      url,
      { documentId },
      {
        responseType: 'blob',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
          Accept: '*/*',
        },
      }
    );

    const ct = resp?.headers?.['content-type'] || '';
    const cd = resp?.headers?.['content-disposition'] || '';

    console.log('⬇️ downloadDocument response:', {
      status: resp.status,
      contentType: ct,
      contentDisposition: cd,
      size: resp?.data?.size,
    });

    // If server returned JSON/HTML (often an error), don’t save it.
    const ctLower = String(ct).toLowerCase();
    const isJson = ctLower.includes('application/json');
    const isHtml = ctLower.includes('text/html');

    if (isJson || isHtml) {
      const text = await blobToText(resp.data);
      let message = 'Download failed';
      try {
        const parsed = JSON.parse(text);
        message = parsed?.message || parsed?.error || message;
      } catch {
        // HTML error or plain text
        message = text?.slice(0, 200) || message;
      }
      throw new Error(message);
    }

    return resp;
  });
}

/**
 * Saves the downloaded blob with the correct extension.
 * Does NOT force PDF.
 */
export async function downloadAndSaveDocuments(documentId, preferredName = '') {
  const resp = await downloadDocument(documentId);

  const ct = resp?.headers?.['content-type'] || 'application/octet-stream';
  const cd = resp?.headers?.['content-disposition'] || '';

  const serverName = getFilenameFromContentDisposition(cd);
  const baseName = String(preferredName || serverName || `document_${documentId}`).trim();

  // Choose extension:
  // 1) from MIME (if meaningful)
  // 2) else from filename
  let ext = extFromMime(ct);
  if (!ext) ext = extFromFilename(baseName);

  const finalName = ensureExtension(baseName, ext);

  // Re-wrap with the server content-type
  const blob = new Blob([resp.data], { type: ct });

  // Optional extra check: if you *think* it’s a PDF but it isn’t, log it.
  if (finalName.toLowerCase().endsWith('.pdf')) {
    const ok = await looksLikePdf(blob);
    if (!ok) {
      console.warn('⚠️ File named .pdf but does not look like a PDF. Likely backend returned non-PDF bytes.');
    }
  }

  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = finalName;
  document.body.appendChild(a);
  a.click();
  a.remove();
  window.URL.revokeObjectURL(url);

  console.log('✅ Download saved:', { documentId, filename: finalName, contentType: ct, size: blob.size });
}
